// 当 Mode 为 "Run Once for All Items" 时，输入是一个名为 $input.all() 的数组
const allItems = $input.all();

// 处理每一项数据（通常 Chat Trigger 只有 1 个 Item）
return allItems.map(item => {
  const newBinary = {};

  // 获取当前 item 中所有的二进制键名 (例如: data0, data1)
  const binaryKeys = Object.keys(item.binary || {});

  // 按照你的要求，提取前 3 张并重命名
  binaryKeys.slice(0, 3).forEach((key, index) => {
    newBinary[`image_${index}`] = item.binary[key];
  });

  // 返回符合 n8n 规范的结构
  return {
    json: item.json,
    binary: newBinary
  };
});

// 只保留 image_0，删除 image_1（如果存在）
for (const item of items) {
  if (item.binary && item.binary.image_1) {
    delete item.binary.image_1;
  }
}

// 可选：如果你想把 image_0 改名成统一的名字（如 "main_image"），取消下面注释
// if (item.binary && item.binary.image_0) {
//   item.binary.main_image = item.binary.image_0;
//   delete item.binary.image_0;
// }

return items;

