// 辅助函数：安全转字符串
const toStr = (v) => (v == null ? '' : String(v).trim());

// 1. 从当前输入（Edit Image1）拿到 data 的 binary
const currentBinary = $input.first()?.binary || {};
const dataBinary = currentBinary.data;   // 你的 Edit Image1 输出叫 data

// 2. 从最早的 If 节点拿到 cp binary（跨节点引用）
let cpBinary = null;
try {
  const ifNode = $("If").first();          // 或 .item 如果你确定是单个 item
  cpBinary = ifNode?.binary?.cp;
} catch (e) {
  // 如果节点名不对或没找到，可加 log
  console.log("无法从 If 节点获取 cp", e);
}

// 3. 准备输出（类似你学习的代码风格）
const hasData = !!dataBinary;
const hasCp   = !!cpBinary;

if (!hasData && !hasCp) {
  return [{ json: { error: "没有找到任何图片 binary" } }];
}

// 可以选择：两个文件都输出为单独 item，或者合并到一个 item
// 这里模仿“每个文件一个 item”的风格
const outputs = [];

if (hasData) {
  outputs.push({
    json: {
      type: "from_edit",
      fileName: dataBinary.fileName || "edit_data.png",
      mimeType: dataBinary.mimeType || "image/png",
      source: "Edit Image1"
    },
    binary: { data: dataBinary }   // 保持原 key 或改名
  });
}

if (hasCp) {
  outputs.push({
    json: {
      type: "from_if",
      fileName: cpBinary.fileName || "if_cp.png",
      mimeType: cpBinary.mimeType || "image/png",
      source: "If 节点"
    },
    binary: { cp: cpBinary }
  });
}

// 如果你想两个文件放在同一个 item 里（更常见）
if (outputs.length === 0) {
  return [{ json: { message: "无图片" } }];
} else if (outputs.length === 1) {
  return outputs;
} else {
  // 两个都存在时，合并成一个 item（推荐下游处理）
  return [{
    json: {
      hasBoth: true,
      dataFileName: dataBinary?.fileName,
      cpFileName: cpBinary?.fileName
    },
    binary: {
      data: dataBinary,
      cp: cpBinary
    }
  }];
}
